const {BigQuery} = require('@google-cloud/bigquery');
const {Storage} = require('@google-cloud/storage');

// Set up BigQuery and Storage clients with credentials
const bigquery = new BigQuery({
  projectId: 'your-project-id',
});

const storage = new Storage({
  keyFilename: 'path/to/credentials.json',
});

exports.processBigData = async (req, res) => {
  try {
    // Set maximum memory allocation to 8GB and timeout to 540 seconds
    process.env.NODE_OPTIONS = '--max-old-space-size=8192 --stack-size=2048';

    const [rows] = await bigquery.dataset('your-dataset-id').table('your-table-id').getMetadata();

    if (!rows) {
      res.status(404).send({message: 'Table not found'});
      return;
    }

    // Aggregate data from BigQuery
    const query = `SELECT * FROM your-table-id`;
    const [job] = await bigquery.createQueryJob({
      query,
      destinationDatasetId: 'your-dataset-id',
      destinationTableId: 'aggregated-data',
    });

    const [results] = await job.getResults();

    // Process aggregated data
    const processedData = results.map((row) => {
      return {
        id: row.id,
        name: row.name,
        age: row.age,
      };
    });

    // Store processed data in Cloud Storage
    const bucketName = 'your-bucket-name';
    const fileName = 'aggregated-data.json';

    const options = {
      destination: `${bucketName}/${fileName}`,
      metadata: {
        contentType: 'application/json',
      },
    };

    storage.bucket(bucketName).upload(processedData, options);

    res.status(200).send({message: 'Data processed successfully'});
  } catch (err) {
    console.error(err);
    res.status(500).send({message: 'Error processing data'});
  }
};